import{_ as t,o as n,c as a,ag as o}from"./chunks/framework.Vng7Hdlh.js";const h=JSON.parse('{"title":"Internal MCP HTTP client (backend)","description":"","frontmatter":{},"headers":[],"relativePath":"BACKEND_MCP_HTTP_CLIENT.md","filePath":"BACKEND_MCP_HTTP_CLIENT.md"}'),r={name:"BACKEND_MCP_HTTP_CLIENT.md"};function l(i,e,c,s,p,d){return n(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="internal-mcp-http-client-backend" tabindex="-1">Internal MCP HTTP client (backend) <a class="header-anchor" href="#internal-mcp-http-client-backend" aria-label="Permalink to &quot;Internal MCP HTTP client (backend)&quot;">​</a></h1><p>Deprecated: Prefer the new Streamable MCP HTTP Client documented in <code>docs/BACKEND_MCP_STREAMABLE_CLIENT.md</code> for new integrations. This legacy client only supports separate request and SSE endpoints.</p><p>This module lets the backend AI call a remote MCP server over HTTP using OAuth, without exposing MCP-over-HTTP routes in our server.</p><p>Location: backend/src/lib/mcp/http-client.ts</p><p>Capabilities</p><ul><li>OAuth discovery: Supports RFC 9728 (resource metadata) and RFC 8414 (AS metadata)</li><li>Grants: client_credentials and token_exchange (with resource/audience)</li><li>Methods: <ul><li>listTools(): Fetches available tools</li><li>callTool({ name, arguments }): Executes a tool</li></ul></li></ul><p>Configuration Provide baseUrl of the external MCP server and one of the following:</p><ul><li>discovery.authorizationServer: URL to AS metadata (/.well-known/openid-configuration or oauth-authorization-server)</li><li>discovery.protectedResource: URL to RS metadata (/.well-known/oauth-protected-resource)</li></ul><p>Add an OAuth grant:</p><ul><li>client_credentials: clientId, clientSecret (or public client with PKCE/token exchange upstream)</li><li>token_exchange: clientId, clientSecret (optional), subjectToken (incoming access token), resource/audience/scope as needed</li></ul><p>Example</p><p>import McpHttpClient from &#39;@/lib/mcp/http-client&#39;</p><p>const client = new McpHttpClient({ baseUrl: &#39;<a href="https://external-mcp.example.com" target="_blank" rel="noreferrer">https://external-mcp.example.com</a>&#39;, discovery: { authorizationServer: &#39;<a href="https://auth.example.com/.well-known/openid-configuration" target="_blank" rel="noreferrer">https://auth.example.com/.well-known/openid-configuration</a>&#39;, // or: protectedResource: &#39;<a href="https://external-mcp.example.com/.well-known/oauth-protected-resource" target="_blank" rel="noreferrer">https://external-mcp.example.com/.well-known/oauth-protected-resource</a>&#39; }, tokenGrant: { type: &#39;client_credentials&#39;, clientId: process.env.MCP_CLIENT_ID!, clientSecret: process.env.MCP_CLIENT_SECRET!, scope: &#39;mcp:tools.read mcp:tools.call&#39; // adjust to server policy } })</p><p>const tools = await client.listTools() const result = await client.callTool({ name: &#39;searchPatients&#39;, arguments: { q: &#39;doe&#39; } })</p><p>Notes</p><ul><li>Tokens are cached in-memory until expiry; reuse client instance per request scope where possible.</li><li>If using token_exchange, pass the subject user&#39;s access token and optionally a resource (the MCP server URL) to constrain audience.</li><li>We intentionally do not implement SSE here. If needed later, add a method that creates an EventSource with the same authorizedFetch helper.</li></ul>',16)])])}const m=t(r,[["render",l]]);export{h as __pageData,m as default};
